#include <omp.h>

#define BLOCK_X 16
#define BLOCK_Y 16
#define PI 3.1415926535897932

int threads_per_block = 512;

long M = INT_MAX;
int A = 1103515245;
int C = 12345;

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38
#endif

long long get_time() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

double elapsed_time(long long start_time, long long end_time) {
    return (double) (end_time - start_time) / (1000 * 1000);
}

double dev_round_double(double value) {
    int newValue = (int) (value);
    if (value - newValue < .5)
        return newValue;
    else
        return newValue + 1;
}

double calcLikelihoodSum(unsigned char * I, int * ind, int numOnes, int index) {
    double likelihoodSum = 0.0;
    int x;
    for(x = 0; x < numOnes; x++)
        likelihoodSum += (pow((double)(I[ind[index*numOnes + x]] - 100), 2) - pow((double)(I[ind[index*numOnes + x]] - 228), 2)) / 50.0;
    return likelihoodSum;
}

void cdfCalc(double * CDF, double * weights, int Nparticles) {
    int x;
    CDF[0] = weights[0];
    for(x = 1; x < Nparticles; x++) {
        CDF[x] = weights[x] + CDF[x-1];
    }
}

double d_randu(int * seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

double d_randn(int * seed, int index) {
    double pi = 3.14159265358979323846;
    double u = d_randu(seed, index);
    double v = d_randu(seed, index);
    double cosine = cos(2 * pi * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

double updateWeights(double * weights, double * likelihood, int Nparticles) {
    int x;
    double sum = 0;
    for(x = 0; x < Nparticles; x++) {
        weights[x] = weights[x] * exp(likelihood[x]);
        sum += weights[x];
    }
    return sum;
}

int findIndexBin(double * CDF, int beginIndex, int endIndex, double value) {
    if(endIndex < beginIndex)
        return -1;
    int middleIndex;
    while(endIndex > beginIndex) {
        middleIndex = beginIndex + ((endIndex - beginIndex) / 2);
        if(CDF[middleIndex] >= value) {
            if(middleIndex == 0)
                return middleIndex;
            else if(CDF[middleIndex - 1] < value)
                return middleIndex;
            else if(CDF[middleIndex - 1] == value) {
                while(CDF[middleIndex] == value && middleIndex >= 0)
                    middleIndex--;
                middleIndex++;
                return middleIndex;
            }
        }
        if(CDF[middleIndex] > value)
            endIndex = middleIndex - 1;
        else
            beginIndex = middleIndex + 1;
    }
    return -1;
}

void find_index(double * arrayX, double * arrayY, double * CDF, double * u, double * xj, double * yj, int Nparticles) {
    int i;
    #pragma omp parallel for
    for(i = 0; i < Nparticles; i++) {
        int index = -1;
        int x;
        for(x = 0; x < Nparticles; x++) {
            if(CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if(index == -1) {
            index = Nparticles - 1;
        }
        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

void normalize_weights(double * weights, int Nparticles, double * partial_sums, double * CDF, double * u, int * seed) {
    int i;
    double sumWeights = partial_sums[0];

    #pragma omp parallel for
    for(i = 0; i < Nparticles; i++) {
        weights[i] = weights[i] / sumWeights;
    }

    cdfCalc(CDF, weights, Nparticles);
    u[0] = (1.0 / ((double)(Nparticles))) * d_randu(seed, 0);

    double u1 = u[0];
    #pragma omp parallel for
    for(i = 0; i < Nparticles; i++) {
        u[i] = u1 + i / ((double)(Nparticles));
    }
}

void sum_kernel(double * partial_sums, int Nparticles, int num_blocks) {
    int x;
    double sum = 0;
    for(x = 0; x < num_blocks; x++) {
        sum += partial_sums[x];
    }
    partial_sums[0] = sum;
}

void likelihood_kernel(double * arrayX, double * arrayY, double * xj, double * yj, double * CDF, 
                       int * ind, int * objxy, double * likelihood, unsigned char * I, 
                       double * u, double * weights, int Nparticles, int countOnes, 
                       int max_size, int k, int IszY, int Nfr, int * seed, 
                       double * partial_sums, int threads_per_block) {
    int i;
    int num_blocks = ceil((double) Nparticles / (double) threads_per_block);

    #pragma omp parallel for
    for(i = 0; i < Nparticles; i++) {
        arrayX[i] = xj[i];
        arrayY[i] = yj[i];
        weights[i] = 1.0 / ((double)(Nparticles));
        arrayX[i] = arrayX[i] + 1.0 + 5.0 * d_randn(seed, i);
        arrayY[i] = arrayY[i] - 2.0 + 2.0 * d_randn(seed, i);
    }

    #pragma omp parallel for
    for(i = 0; i < Nparticles; i++) {
        int y;
        int indX, indY;
        for(y = 0; y < countOnes; y++) {
            indX = dev_round_double(arrayX[i]) + objxy[y * 2 + 1];
            indY = dev_round_double(arrayY[i]) + objxy[y * 2];
            ind[i * countOnes + y] = abs(indX * IszY * Nfr + indY * Nfr + k);
            if(ind[i * countOnes + y] >= max_size)
                ind[i * countOnes + y] = 0;
        }
        likelihood[i] = calcLikelihoodSum(I, ind, countOnes, i);
        likelihood[i] = likelihood[i] / countOnes;
        weights[i] = weights[i] * exp(likelihood[i]);
    }

    for(i = 0; i < num_blocks; i++) {
        partial_sums[i] = 0.0;
    }

    #pragma omp parallel for
    for(i = 0; i < Nparticles; i++) {
        int block_id = i / threads_per_block;
        partial_sums[block_id] += weights[i];
    }
}

void setIf(int testValue, int newValue, unsigned char * array3D, int * dimX, int * dimY, int * dimZ) {
    int x, y, z;
    for(x = 0; x < *dimX; x++) {
        for(y = 0; y < *dimY; y++) {
            for(z = 0; z < *dimZ; z++) {
                if(array3D[x * *dimY * *dimZ + y * *dimZ + z] == testValue)
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
            }
        }
    }
}

void addNoise(unsigned char * array3D, int * dimX, int * dimY, int * dimZ, int * seed) {
    int x, y, z;
    for(x = 0; x < *dimX; x++) {
        for(y = 0; y < *dimY; y++) {
            for(z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] = array3D[x * *dimY * *dimZ + y * *dimZ + z] + (unsigned char)(5 * d_randn(seed, 0));
            }
        }
    }
}

void strelDisk(int * disk, int radius) {
    int diameter = radius * 2 - 1;
    int x, y;
    for(x = 0; x < diameter; x++) {
        for(y = 0; y < diameter; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) + pow((double)(y - radius + 1), 2));
            if(distance < radius)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

void dilate_matrix(unsigned char * matrix, int posX, int posY, int posZ, int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while(startX < 0) startX++;
    int startY = posY - error;
    while(startY < 0) startY++;
    int endX = posX + error;
    while(endX > dimX) endX--;
    int endY = posY + error;
    while(endY > dimY) endY--;
    int x, y;
    for(x = startX; x < endX; x++) {
        for(y = startY; y < endY; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) + pow((double)(y - posY), 2));
            if(distance < error)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

void imdilate_disk(unsigned char * matrix, int dimX, int dimY, int dimZ, int error, unsigned char * newMatrix) {
    int x, y, z;
    for(z = 0; z < dimZ; z++) {
        for(x = 0; x < dimX; x++) {
            for(y = 0; y < dimY; y++) {
                if(matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors(int * se, int numOnes, int * neighbors, int radius) {
    int x, y;
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for(x = 0; x < diameter; x++) {
        for(y = 0; y < diameter; y++) {
            if(se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

void videoSequence(unsigned char * I, int IszX, int IszY, int Nfr, int * seed) {
    int k;
    int max_size = IszX * IszY * Nfr;
    int x0 = (int)dev_round_double(IszY / 2.0);
    int y0 = (int)dev_round_double(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    int xk, yk, pos;
    for(k = 1; k < Nfr; k++) {
        xk = abs(x0 + (k - 1));
        yk = abs(y0 - 2 * (k - 1));
        pos = yk * IszY * Nfr + xk * Nfr + k;
        if(pos >= max_size)
            pos = 0;
        I[pos] = 1;
    }

    unsigned char * newMatrix = (unsigned char *)calloc(IszX * IszY * Nfr, sizeof(unsigned char));
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);
    int x, y;
    for(x = 0; x < IszX; x++) {
        for(y = 0; y < IszY; y++) {
            for(k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] = newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);
    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

int findIndex(double * CDF, int lengthCDF, double value) {
    int index = -1;
    int x;
    for(x = 0; x < lengthCDF; x++) {
        if(CDF[x] >= value) {
            index = x;
            break;
        }
    }
    if(index == -1) {
        return lengthCDF - 1;
    }
    return index;
}

int particleFilter(unsigned char * I, int IszX, int IszY, int Nfr, int * seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;
    double xe = dev_round_double(IszY / 2.0);
    double ye = dev_round_double(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int * disk = (int *)calloc(diameter * diameter, sizeof(int));
    strelDisk(disk, radius);
    int countOnes = 0;
    int x, y;
    for(x = 0; x < diameter; x++) {
        for(y = 0; y < diameter; y++) {
            if(disk[x * diameter + y] == 1)
                countOnes++;
        }
    }
    int * objxy = (int *)calloc(countOnes * 2, sizeof(int));
    getneighbors(disk, countOnes, objxy, radius);

    double * weights = (double *)calloc(Nparticles, sizeof(double));
    for(x = 0; x < Nparticles; x++) {
        weights[x] = 1.0 / ((double)(Nparticles));
    }

    double * likelihood = (double *)calloc(Nparticles + 1, sizeof(double));
    double * arrayX = (double *)calloc(Nparticles, sizeof(double));
    double * arrayY = (double *)calloc(Nparticles, sizeof(double));
    double * xj = (double *)calloc(Nparticles, sizeof(double));
    double * yj = (double *)calloc(Nparticles, sizeof(double));
    double * CDF = (double *)calloc(Nparticles, sizeof(double));

    int * ind = (int *)calloc(countOnes * Nparticles, sizeof(int));
    double * u = (double *)calloc(Nparticles, sizeof(double));
    double * partial_sums = (double *)calloc(Nparticles + 1, sizeof(double));

    int num_blocks = ceil((double)Nparticles / (double)threads_per_block);

    for(x = 0; x < Nparticles; x++) {
        xj[x] = xe;
        yj[x] = ye;
    }

    int k;
    int indX, indY;

    long long send_start = get_time();

    printf("TIME TO SEND TO GPU: %f\n", elapsed_time(send_start, get_time()));
    printf("threads_per_block=%d\n", threads_per_block);

    for(k = 1; k < Nfr; k++) {
        likelihood_kernel(arrayX, arrayY, xj, yj, CDF, ind, objxy, likelihood, I, u, weights, 
                         Nparticles, countOnes, max_size, k, IszY, Nfr, seed, partial_sums, threads_per_block);

        sum_kernel(partial_sums, Nparticles, num_blocks);

        normalize_weights(weights, Nparticles, partial_sums, CDF, u, seed);

        xe = 0;
        ye = 0;
        double total = 0.0;
        for(x = 0; x < Nparticles; x++) {
            xe += arrayX[x] * weights[x];
            ye += arrayY[x] * weights[x];
            total += weights[x];
        }
        printf("total weight: %lf\n", total);
        printf("XE: %lf\n", xe);
        printf("YE: %lf\n", ye);
        double distance = sqrt(pow((double)(xe - (int)dev_round_double(IszY / 2.0)), 2) + pow((double)(ye - (int)dev_round_double(IszX / 2.0)), 2));
        printf("%lf\n", distance);

        find_index(arrayX, arrayY, CDF, u, xj, yj, weights, Nparticles);
    }

    long long back_time = get_time();
    long long free_time = get_time();
    long long back_end_time = get_time();

    printf("GPU Execution: %lf\n", elapsed_time(send_start, back_time));
    printf("FREE TIME: %lf\n", elapsed_time(back_time, free_time));
    printf("SEND TO SEND BACK: %lf\n", elapsed_time(back_time, back_end_time));

    xe = 0;
    ye = 0;
    for(x = 0; x < Nparticles; x++) {
        xe += arrayX[x] * weights[x];
        ye += arrayY[x] * weights[x];
    }
    double distance = sqrt(pow((double)(xe - (int)dev_round_double(IszY / 2.0)), 2) + pow((double)(ye - (int)dev_round_double(IszX / 2.0)), 2));

    FILE *fid;
    fid = fopen("output.txt", "w+");
    if(fid == NULL) {
        printf("The file was not opened for writing\n");
        return -1;
    }
    fprintf(fid, "XE: %lf\n", xe);
    fprintf(fid, "YE: %lf\n", ye);
    fprintf(fid, "distance: %lf\n", distance);
    fclose(fid);

    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(ind);
    free(u);
    free(partial_sums);
    free(weights);
    free(disk);
    free(objxy);

    return 0;
}

